import{_ as o,o as a,c as t,ag as i}from"./chunks/framework.DwYrYzXn.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"packages/astro/CHANGELOG.md","filePath":"packages/astro/CHANGELOG.md"}'),n={name:"packages/astro/CHANGELOG.md"};function r(l,e,d,c,s,u){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to the <code>@magmacomputing/tempo-plugin-astro</code> project will be documented in this file.</p><h2 id="_1-1-6-2026-06-11" tabindex="-1">[1.1.6] - 2026-06-11 <a class="header-anchor" href="#_1-1-6-2026-06-11" aria-label="Permalink to &quot;[1.1.6] - 2026-06-11&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Renamed the metadata payload property <code>type</code> to <code>event</code> (Equinox vs. Solstice) to better reflect astronomical terminology and reduce naming collisions.</li><li>Refactored internal <code>calculateAstroMoment</code> parameter from <code>season</code> to <code>quarter</code> to resolve semantic ambiguity between meteorological seasons and astronomical quarters.</li><li>Augmented the <code>@magmacomputing/tempo/core</code> module to natively type the <code>TempoTermRegistry</code> for <code>astro</code> and <code>astronomy</code>, providing full strict IntelliSense autocomplete for IDEs.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Type Definitions</strong>: Added missing <code>start: Tempo</code> and <code>end: Tempo</code> boundaries to the <code>TempoTermRegistry</code> augmentation, ensuring accurate typings for the dynamic range boundaries injected by the core resolver.</li><li><strong>NPM Registry Metadata</strong>: Explicitly added <code>README.md</code>, <code>CHANGELOG.md</code>, and <code>LICENSE</code> to the <code>files</code> array in <code>package.json</code> to ensure the npmjs.com registry correctly renders package documentation.</li></ul><h2 id="_1-1-3-2026-06-07" tabindex="-1">[1.1.3] - 2026-06-07 <a class="header-anchor" href="#_1-1-3-2026-06-07" aria-label="Permalink to &quot;[1.1.3] - 2026-06-07&quot;">​</a></h2><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>Migrated licensing enforcement from <code>jose</code> to the native WebCrypto Tempo Core primitives.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Replaced all usage of the global <code>Date</code> object with the <code>instant()</code> temporal engine in the core validator to ensure timeline consistency.</li><li>Corrected test environment resolution boundaries that caused unhandled asynchronous Promise verification leaks.</li></ul><h2 id="_1-1-2-2026-06-04" tabindex="-1">[1.1.2] - 2026-06-04 <a class="header-anchor" href="#_1-1-2-2026-06-04" aria-label="Permalink to &quot;[1.1.2] - 2026-06-04&quot;">​</a></h2><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Resolved the &quot;Ghost-Trap&quot; architectural conflict that prevented validation when used with Tempo v3.0.0.</li><li>Decoupled <code>definePremiumTerm</code> and cryptographic validation from the plugin bundle. Licensing engine state and references are now directly imported from the Tempo Core (<code>@magmacomputing/tempo/plugin</code>).</li><li>Removed the <code>@magmacomputing/tempo-plugin-core</code> bundled <code>devDependency</code> to prevent duplicate initialization.</li></ul><h2 id="_1-0-2-2026-05-25" tabindex="-1">[1.0.2] - 2026-05-25 <a class="header-anchor" href="#_1-0-2-2026-05-25" aria-label="Permalink to &quot;[1.0.2] - 2026-05-25&quot;">​</a></h2><h3 id="security-1" tabindex="-1">Security <a class="header-anchor" href="#security-1" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>Migrated licensing enforcement to the newly decoupled <code>@magmacomputing/tempo-plugin-core</code> workspace.</li><li>The proprietary license verification and string-obfuscation logic is now baked directly into the plugin bundle during the build step, decentralizing the security model and eliminating reliance on the open-source engine for validation.</li><li>Updated <code>devDependencies</code> to automatically resolve the new internal <code>@core</code> monorepo symlink via <code>tsup</code>.</li></ul><h2 id="_1-0-0-2026-05-18" tabindex="-1">[1.0.0] - 2026-05-18 <a class="header-anchor" href="#_1-0-0-2026-05-18" aria-label="Permalink to &quot;[1.0.0] - 2026-05-18&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Initial release of the Astronomical Seasons plugin.</li><li>Implements the Jean Meeus polynomial approximation algorithm for precise Equinox and Solstice moments.</li><li>Returns fully scoped astronomical objects containing: <ul><li>Precise start/end dates for each astronomical season</li><li>The astronomical <code>key</code> (Vernal, Summer, Autumnal, Winter)</li><li>The colloquial traditional <code>season</code> mapping (Spring, Summer, Autumn, Winter)</li><li>The <code>event</code> (Equinox vs. Solstice)</li></ul></li><li>Fully supports automatic label inversion for Northern vs. Southern hemisphere configurations (<code>sphere: &#39;south&#39;</code>).</li><li>Implements the <code>v2.10.0</code> Tempo Core Licensing API via cryptographic JSON Web Signatures (JWS).</li><li>Auto-registers itself via side-effect upon import.</li></ul>',21)])])}const p=o(n,[["render",r]]);export{m as __pageData,p as default};
